skinparam classAttributeIconSize 0

class DrawingObject {
  virtual void Draw()
}

class Circle {
  override void Draw()
}

class Square {
  override void Draw()
}

class Line {
  override void Draw()
}

class Rectangle {
  new void Draw()
}

Circle --|> DrawingObject
Square --|> DrawingObject
Line --|> DrawingObject
Rectangle --|> Square
@enduml
